import React from 'react';
import * as LabelPrimitive from '@radix-ui/react-label';
import { getLabelClassKeys } from '../lib/core';
import type { LabelBaseProps } from '../lib/core';
import styles from './label.module.scss';

export interface LabelProps extends React.LabelHTMLAttributes<HTMLLabelElement>, LabelBaseProps {}

const Label = React.forwardRef<HTMLLabelElement, LabelProps>(({ className = '', required, children, ...props }, ref) => {
	const classKeys = getLabelClassKeys(required);

	return (
		<LabelPrimitive.Root ref={ref} className={`${styles[classKeys.base]} ${classKeys.required ? styles[classKeys.required] : ''} ${className}`} {...props}>
			{children}
		</LabelPrimitive.Root>
	);
});

Label.displayName = 'Label';

export { Label };
export default Label;

@use '../../../styles/variables/colors' as *;

.label {
	display: block;
	font-size: $text-sm;
	font-weight: $font-medium;
	color: $foreground;
	line-height: $leading-normal;
	cursor: pointer;

	&.required::after {
		content: ' *';
		color: $destructive;
	}
}
